    discount_percentage = 0      # Initialize a variable to hold our calculated discounts percentage (default is no discout)    
    if user['role'] == 'enterprise':       # If User role equals enterprise, apply 30% off on cart total. Otherwise only the payment will be processed  
        discount_percentage = 30      # Set Discounts to get a full price of items for Enterprise users (discounted by default)    
    elif user['role'] == 'premium':       # If User role equals premium, apply 15% off on cart total. Otherwise only the payment will be processed  
        discount_percentage = 15      # Set Discounts to get a full price of items for Premium users (discounted by default)    
